-- users table\nCREATE TABLE users (\n    user_id SERIAL PRIMARY KEY,\n    username VARCHAR(50) UNIQUE NOT NULL,\n    password VARCHAR(255) NOT NULL,\n    email VARCHAR(100) UNIQUE NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP\n);\n\n-- borrowers table\nCREATE TABLE borrowers (\n    borrower_id SERIAL PRIMARY KEY,\n    user_id INT REFERENCES users(user_id),\n    full_name VARCHAR(100) NOT NULL,\n    identification_number VARCHAR(50) UNIQUE NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP\n);\n\n-- loans table\nCREATE TABLE loans (\n    loan_id SERIAL PRIMARY KEY,\n    borrower_id INT REFERENCES borrowers(borrower_id),\n    amount DECIMAL(10, 2) NOT NULL,\n    interest_rate DECIMAL(5, 2) NOT NULL,\n    start_date TIMESTAMP NOT NULL,\n    end_date TIMESTAMP NOT NULL,\n    status VARCHAR(50) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP\n);\n\n-- repayments table\nCREATE TABLE repayments (\n    repayment_id SERIAL PRIMARY KEY,\n    loan_id INT REFERENCES loans(loan_id),\n    amount DECIMAL(10, 2) NOT NULL,\n    repayment_date TIMESTAMP NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP\n);\n\n-- collaterals table\nCREATE TABLE collaterals (\n    collateral_id SERIAL PRIMARY KEY,\n    loan_id INT REFERENCES loans(loan_id),\n    type VARCHAR(50) NOT NULL,\n    description TEXT NOT NULL,\n    value DECIMAL(10, 2) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP\n);\n\n-- savings table\nCREATE TABLE savings (\n    saving_id SERIAL PRIMARY KEY,\n    user_id INT REFERENCES users(user_id),\n    amount DECIMAL(10, 2) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP\n);\n\n-- investors table\nCREATE TABLE investors (\n    investor_id SERIAL PRIMARY KEY,\n    user_id INT REFERENCES users(user_id),\n    total_investment DECIMAL(10, 2) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP\n);\n\n-- audit logs table\nCREATE TABLE audit_logs (\n    log_id SERIAL PRIMARY KEY,\n    action VARCHAR(255) NOT NULL,\n    table_name VARCHAR(50) NOT NULL,\n    row_id INT NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n